const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const bundle = payload.context_bundle && typeof payload.context_bundle === 'object' ? payload.context_bundle : payload;
const rawQuery = typeof payload.message === 'string' ? payload.message : (typeof payload.query === 'string' ? payload.query : bundle.query);
const buildError = (code, message) => [{ json: { ok: false, error: { code, message }, query: null, project_slug: null, top_k: null, retrieval: { strategy: 'project-first-fallback-general', project_match_count: 0, general_match_count: 0, memory_count: 0, strongest_similarity: null, similarity_threshold: 0.72, empty: true }, sources: [], context_preview: '', trace: { workflow_chain: ['crispybrain-answer-from-memory'], stage: 'validation' }, session: { turn_count_before: 0, history_used: false, stored: false } } }];
if (typeof rawQuery !== 'string' || rawQuery.trim() === '') return buildError('INVALID_INPUT', 'Missing or invalid query/message');
const retrieval = bundle.retrieval && typeof bundle.retrieval === 'object' ? bundle.retrieval : { strategy: 'project-first-fallback-general', project_match_count: 0, general_match_count: 0, memory_count: 0, strongest_similarity: null, similarity_threshold: 0.72, empty: true };
const sources = Array.isArray(bundle.sources) ? bundle.sources : [];
const session = bundle.session && typeof bundle.session === 'object' ? bundle.session : { turn_count_before: 0, history_used: false, stored: false };
const context = typeof bundle.context === 'string' ? bundle.context : '';
const prompt = typeof bundle.prompt === 'string' ? bundle.prompt : '';
const projectSlug = typeof bundle.project_slug === 'string' && bundle.project_slug.trim() ? bundle.project_slug.trim() : (typeof payload.project_slug === 'string' && payload.project_slug.trim() ? payload.project_slug.trim() : null);
const topK = Number.isInteger(payload.top_k) ? payload.top_k : (Number.isInteger(bundle.top_k) ? bundle.top_k : 5);
const query = rawQuery.trim();
const simplifyRequested = /\b(explain that more simply|explain simply|simplify|simpler|more simply|plain english|plain terms)\b/i.test(query);
const improvedPrompt = [
  prompt,
  simplifyRequested ? 'When simplifying, preserve the core meaning and keep the key concepts from the source context, especially memory, retrieval, and system behavior. Reduce complexity without becoming generic, and do not replace specific ideas with vague wording.' : null
].filter(Boolean).join('\n\n');
return [{ json: { request_ok: true, skip_generation: retrieval.empty === true || !context.trim() || !improvedPrompt.trim(), query, project_slug: projectSlug, top_k: topK, retrieval, sources, context, context_preview: typeof bundle.context_preview === 'string' ? bundle.context_preview : context.slice(0, 280), prompt: improvedPrompt, trace: bundle.trace ?? { workflow_chain: ['crispybrain-answer-from-memory'] }, session } }];

const base = $('Normalize Answer Request').first().json;
const statusCode = $json.statusCode ?? 0;
const body = $json.body ?? {};
const answer = typeof body.response === 'string' ? body.response.trim() : '';
if (statusCode < 200 || statusCode >= 300 || answer === '') {
  return [{ json: { ok: false, error: { code: 'OLLAMA_GENERATION_FAILED', message: 'Ollama answer generation failed', status: statusCode || null, details: body.error ?? null }, query: base.query, project_slug: base.project_slug ?? null, top_k: base.top_k, retrieval: base.retrieval, sources: base.sources, context_preview: base.context_preview, trace: { ...base.trace, workflow_chain: ['crispybrain-answer-from-memory'], stage: 'generation' }, session: base.session } }];
}
return [{ json: { ok: true, answer, query: base.query, project_slug: base.project_slug ?? null, top_k: base.top_k, retrieval: base.retrieval, sources: base.sources, context_preview: base.context_preview, trace: { ...base.trace, workflow_chain: ['crispybrain-answer-from-memory'], stage: 'generation' }, session: base.session } }];
